    public function getCompany($managerId, ?int $organizationId = null)
    {
        $txt = "";
        $organizationFilter = '';
        if ($organizationId !== null) {
            $organizationFilter = $this->db->placehold(" AND organization_id = ?", $organizationId);
        }
        
        if (gettype($managerId) !== 'string') {
            $query = $this->db->placehold("
            SELECT company  
            FROM manager_company
            WHERE manager_id = ?" . $organizationFilter . "
            LIMIT 1
        ", $managerId);
            $txt = "company";
        } else {
            $organizationFilter = '';
            if ($organizationId !== null) {
                $organizationFilter = $this->db->placehold(" AND mc.organization_id = ?", $organizationId);
            }
            $query = $this->db->placehold("
