    /**
     * Проверка специальных разрешений для конкретных менеджеров
     * @param int $manager_id
     * @param string $permission
     * @return bool
     */
    private function has_special_permission(int $manager_id, string $permission): bool
    {
        $special_permissions = [
            'cession' => [self::MANAGER_POZDNJAKOV_SV],
            'client_cession_info' => [
                self::MANAGER_SMIRNOV_DV,
                self::MANAGER_SHVEC_LAWYER,
                self::MANAGER_SMIRNOVA_TA,
                self::MANAGER_POZDNJAKOV_SV,
                self::MANAGER_SMIRNOVA_TA,
                self::MANAGER_SARAIKINA_SN,
            ]
        ];
        
        return isset($special_permissions[$permission]) && 
               in_array($manager_id, $special_permissions[$permission]);
    }

