    public function check_password($login, $password)
    {
        $password = $this->hash_password($password);
    	$query = $this->db->placehold("
            SELECT id 
            FROM __managers 
            WHERE login = ?
            AND password = ?
        ", $login, $password);
        $this->db->query($query);
        return $this->db->result('id');        
    }

    /**
     * @param string $password
     * @return string
     */
    private function hash_password(string $password): string
    {
        return md5(sha1($this->salt . $password) . $this->salt);
    }

    /**
     * Отчёт по эфеективности работников КЦ по отвалам
     * @param array $filter_data
     * @return array|false
     */
    public function getMissingsOrdersCC(array $filter_data)
    {
        $where = [];
        $where_phone = [];
        $filter_duration = $filter_data['filter_duration'] ?? 30;
        $sql =
            "SELECT
                u.missing_manager_id,
                m.name_1c,
                COUNT(o.id) as total_orders,
                SUM(IF(o.have_close_credits = 0, (
                        u.personal_data_added = 1 AND DATE(u.personal_data_added_date) = DATE(o.date)
                    AND u.address_data_added = 1 AND DATE(u.additional_data_added_date) = DATE(o.date)
                    AND u.accept_data_added = 1 AND DATE(u.accept_data_added_date) = DATE(o.date)
                    AND u.card_added = 1 AND DATE(u.card_added_date) = DATE(o.date)
                    AND u.files_added = 1 AND DATE(u.files_added_date) = DATE(o.date)
                    AND u.additional_data_added = 1 AND DATE(u.additional_data_added_date) = DATE(o.date)), 0)) as total_bad_orders, -- отвалы
                SUM(IF(o.confirm_date IS NULL, 0, 1)) as total_confired_orders, -- выданные займы
                SUM((
                    SELECT COUNT(DISTINCT mc.to_number) FROM s_mangocalls mc WHERE
                        mc.manager_id = u.missing_manager_id
                        AND mc.duration >= $filter_duration -- время разговора в сек.
                        AND mc.to_number = u.phone_mobile -- исходящие из КЦ клиенту
                        AND DATE(o.date) = DATE(mc.created)
                        -- {{where_phone}}
                )) as total_calls,
               SUM(
                    EXISTS(SELECT * FROM s_mangocalls mc WHERE
                        mc.manager_id = u.missing_manager_id                                     
                        AND o.confirm_date IS NOT NULL   
                        AND DATE(o.confirm_date) = DATE(mc.created)                                                         
                        AND mc.duration >= $filter_duration -- время разговора в сек.
                        AND mc.to_number = u.phone_mobile -- исходящие из КЦ клиенту
                        -- {{where_phone}}
                    )
                ) as total_orders_with_confirmed,
                SUM(
                    IF(EXISTS(SELECT * FROM s_mangocalls mc WHERE
                        mc.manager_id = u.missing_manager_id                                     
                        AND o.confirm_date IS NOT NULL   
                        AND DATE(o.confirm_date) = DATE(mc.created)                                                         
                        AND mc.duration >= $filter_duration -- время разговора в сек.
                        AND mc.to_number = u.phone_mobile -- исходящие из КЦ клиенту
                        -- {{where_phone}}
                    ), o.amount, 0)
                ) as total_amount
                FROM 
                    s_orders o
                    LEFT JOIN s_users u ON u.id = o.user_id
                    LEFT JOIN s_managers m ON m.id = u.missing_manager_id
            WHERE 1 = 1
                -- {{where}}
                GROUP BY u.missing_manager_id
        ";

        // даты заявки
        if (!empty($filter_data['filter_date_order'])) {
            $where[] = $this->db->placehold("DATE(o.date) BETWEEN DATE(?) AND DATE(?)", $filter_data['filter_date_order']['filter_date_start'], $filter_data['filter_date_order']['filter_date_end']);
            $where_phone[] = $this->db->placehold("mc.created BETWEEN ? AND ?", $filter_data['filter_date_order']['filter_date_start'], $filter_data['filter_date_order']['filter_date_end']);
        }

        // фильтр по менеджерам
        if (!empty($filter_data['filter_manager_ids'])) {
            $where[] = $this->db->placehold("u.missing_manager_id IN (?@)", $filter_data['filter_manager_ids']);
        }

        $query = strtr($sql, [
            '-- {{where_phone}}' => !empty($where_phone) ? "AND " . implode(" AND ", $where_phone) : '',
            '-- {{where}}' => !empty($where) ? "AND " . implode(" AND ", $where) : '',
        ]);
        $this->db->query($query);
        return $this->db->results();
    }

    public function get_verificators()
    {
        $query = "SELECT * FROM __managers WHERE role = 'verificator' OR role = 'edit_verificator'";
        $this->db->query($query);
        return $this->db->results();
    }

    /**
     * Проверка, может ли роль заниматься верификацией заявок
     *
     * @param string $role
     * @return bool
     */
    public function canVerify(string $role): bool
    {
        // Список ролей‑верификаторов собран в одном месте,
        // чтобы при изменениях не править проверки по всему коду
        $verificatorRoles = [
            'verificator',
            'edit_verificator',
            'verificator_minus',
        ];

        return in_array($role, $verificatorRoles, true);
    }

    public function getCompanyManagers($plus, $minus, ?int $organizationId = null)
    {
        $organizationFilter = '';
        if ($organizationId !== null) {
            $organizationFilter = $this->db->placehold(" AND manager_company.organization_id = ?", $organizationId);
        }
        
        $query = $this->db->placehold("SELECT s_managers.id, s_managers.name FROM manager_company 
                    LEFT JOIN s_managers on s_managers.id = manager_company.manager_id 
                                      where manager_company.company is not null 
                                      and manager_company.plus = ? and manager_company.minus = ?" . $organizationFilter, (bool)$plus, $minus);

        $this->db->query($query);
        return $this->db->results();
    }

    public function add_schedule($date, $managers, $plus, ?int $organizationId = null)
    {
        $organizationFilter = '';
        if ($organizationId !== null) {
            $organizationFilter = $this->db->placehold(" AND organization_id = ?", $organizationId);
        }
        
        $query = $this->db->placehold("
            DELETE FROM managers_schedule 
                   WHERE date = ?
                   AND plus = ?" . $organizationFilter, (string)$date, (bool)$plus);
        $this->db->query($query);

        foreach ($managers as $manager){
            $query = $this->db->placehold("
            INSERT INTO managers_schedule (manager_id, date, plus, organization_id)
            VALUES (?, ?, ?, ?);
        ", (int)$manager, (string)$date, (bool)$plus, $organizationId);
            $this->db->query($query);
        }
    }

    public function getScheduledManagers($date, $plus, ?int $organizationId = null)
    {
        $organizationFilter = '';
        if ($organizationId !== null) {
            $organizationFilter = $this->db->placehold(" AND managers_schedule.organization_id = ?", $organizationId);
        }
        
        $query = $this->db->placehold("SELECT s_managers.id, s_managers.name,s_managers.role FROM managers_schedule
                    LEFT JOIN s_managers on s_managers.id = managers_schedule.manager_id 
                    where managers_schedule.date = ?
                    and plus = ?" . $organizationFilter, (string) $date, (bool)$plus);
        $this->db->query($query);
        return $this->db->results();
    }

    public function update_manager_data($id, $manager)
    {
        $query = $this->db->placehold("
            UPDATE __managers SET ?% WHERE id = ?
        ", (array) $manager, (int)$id);
        $this->db->query($query);
        return $id;
    }

    public function getDeletedManager()
    {
        $query = $this->db->placehold("
            SELECT id as manager_id 
            FROM __managers
            WHERE vox_deleted = true
        ");
        $this->db->query($query);
        return $this->db->results();
    }

    /**
     * @return array|false
     */
    public function getManagers($plus, $minus, ?int $organizationId = null)
    {
        if ($plus) {
            $role = $this->db->placehold("__managers.role = 'contact_center_new' OR __managers.role = 'contact_center_new_robo'");
        }else if (!$plus && $minus === 'false'){
            $role = $this->db->placehold("__managers.role = 'contact_center' OR __managers.role = 'contact_center_robo'");
        }else if($minus) {
            $role = $this->db->placehold("__managers.role = 'robot_minus'");
        }
        $query = $this->db->placehold("
            SELECT __managers.id, __managers.name,manager_company.company,manager_company.dnc_number
            FROM __managers
            LEFT JOIN manager_company on __managers.id = manager_company.manager_id AND manager_company.organization_id <=> ?
            Where $role ORDER BY __managers.id ASC                                                          
        ", $organizationId);
        $this->db->query($query);
        return $this->db->results();
    }

    /**
     * @param int $managerId
     * @return false|int
     */
    public function getVoxManager(int $managerId, ?int $organizationId = null)
    {
        $query = $this->db->placehold("
            SELECT id, company, dnc_number 
            FROM manager_company 
            WHERE manager_id = ? 
              AND organization_id <=> ?
            LIMIT 1 
        ", $managerId, $organizationId);
        $this->db->query($query);

        return $this->db->result();
    }

    /**
     * @param array $data
     * @return mixed
     */
    public function insertVoxData(array $data, ?int $organizationId = null)
    {
        $data['organization_id'] = $organizationId;

        $query = $this->db->placehold("
            INSERT INTO manager_company SET ?%
        ", $data);
        $this->db->query($query);
        return $this->db->insert_id();
    }

    /**
     * @param int $managerId
     * @param array $data
     * @return void
     */
    public function updateVoxData(int $managerId, array $data, ?int $organizationId = null)
    {
        $query = $this->db->placehold("
            UPDATE manager_company 
            SET ?% 
            WHERE manager_id = ?
              AND organization_id <=> ?
        ", $data, $managerId, $organizationId);
        $this->db->query($query);
    }

    /**
     * Проверка онлайн статуса менеджера
     *
     * @param int $managerId ID менеджера
     * @return bool
     */
    public function isManagerOnline(int $managerId): bool
    {
        $this->db->query("
            SELECT COUNT(*) as is_online
            FROM __managers
            WHERE id = ?
            AND last_visit > DATE_SUB(NOW(), INTERVAL 5 MINUTE)
        ", $managerId);

        $result = $this->db->result();
        return $result->is_online > 0;
    }

    public function add(int $managerId)
    {
        $this->db->query($this->db->placehold('INSERT INTO __manager_visits SET ?%', [
            'manager_id' => $managerId,
            'ip' => $_SERVER['REMOTE_ADDR'],
            'date_create' => date('Y-m-d H:i:s'),
            'last_visit' => date('Y-m-d H:i:s')
        ]));
    }

    public function update(int $managerId)
    {
        $this->db->query($this->db->placehold("SELECT * FROM __manager_visits WHERE manager_id = ? AND ip = ? ORDER BY id DESC LIMIT 1", $managerId, $_SERVER['REMOTE_ADDR']));
        empty($row = $this->db->result()) ? $this->add($managerId) :  $this->db->query($this->db->placehold("UPDATE __manager_visits SET ?% WHERE id = ?", ['last_visit' => date('Y-m-d H:i:s')], $row->id));
    }
}
